class SegmentTree {

public:

    int n;

    T defVal;

    function<T(T, T)> operation;

    vector<T> data;

    SegmentTree(int n, T defVal, function<T(T, T)> operation) : n(n), defVal(defVal), operation(operation) {

        data.assign(2 * n, defVal);

    }

    void update(int i, T val) {

        i += n;

        data[i] = val;

        while(i > 1) {

            i >>= 1;

            data[i] = operation(data[i << 1], data[i << 1 | 1]);

        }

    }

    T query(int l, int r) {

        T res = defVal;

        l += n, r += n;

        while(l < r) {

            if(l & 1) {

                res = operation(res, data[l]);

                l++;

            }

            if(r & 1) {

                r--;

                res = operation(res, data[r]);

            }

            l >>= 1, r >>= 1;

        }

        return res;

    }

};

